from dataclasses import dataclass, field
from datetime import date, time
from typing import Optional


@dataclass
class OfficeHoursSession:
    session_id: str
    session_date: date
    host: str
    scheduled_duration_minutes: int
    questions_submitted_in_advance: list[str]
    attendees: int
    topics_covered: list[str]
    action_items: list[str]
    recording_available: bool
    notes_published_to_wiki: bool

    def was_effective(self) -> bool:
        return (
            self.attendees >= 3
            and len(self.topics_covered) >= 1
            and self.notes_published_to_wiki
        )

    def summary(self) -> str:
        topics = ", ".join(self.topics_covered) if self.topics_covered else "None covered"
        actions = "\n".join(f"  -> {a}" for a in self.action_items) if self.action_items else "  None"
        return (
            f"Office Hours {self.session_id} ({self.session_date})\n"
            f"Host: {self.host} | Attendees: {self.attendees} | "
            f"Duration: {self.scheduled_duration_minutes} min\n"
            f"Topics covered: {topics}\n"
            f"Action items:\n{actions}\n"
            f"Recording: {'Yes' if self.recording_available else 'No'} | "
            f"Notes published: {'Yes' if self.notes_published_to_wiki else 'No'}"
        )


@dataclass
class OfficeHoursTracker:
    sessions: list[OfficeHoursSession] = field(default_factory=list)

    def average_attendance(self) -> float:
        if not self.sessions:
            return 0.0
        return sum(s.attendees for s in self.sessions) / len(self.sessions)

    def notes_publication_rate(self) -> float:
        if not self.sessions:
            return 0.0
        return sum(1 for s in self.sessions if s.notes_published_to_wiki) / len(self.sessions)

    def top_topics(self) -> dict[str, int]:
        counts: dict[str, int] = {}
        for session in self.sessions:
            for topic in session.topics_covered:
                counts[topic] = counts.get(topic, 0) + 1
        return dict(sorted(counts.items(), key=lambda x: x[1], reverse=True))

    def health_report(self) -> str:
        avg = self.average_attendance()
        pub_rate = self.notes_publication_rate()
        topics = self.top_topics()
        top3 = list(topics.keys())[:3]
        status = "GREEN" if avg >= 4 and pub_rate >= 0.8 else "AMBER" if avg >= 2 else "RED"
        return (
            f"Office Hours health: {status}\n"
            f"Sessions run: {len(self.sessions)}\n"
            f"Avg attendance: {avg:.1f}\n"
            f"Notes publication rate: {pub_rate:.0%}\n"
            f"Top recurring topics: {', '.join(top3) if top3 else 'None yet'}"
        )


tracker = OfficeHoursTracker(sessions=[
    OfficeHoursSession(
        session_id="OH-2026-07-W1",
